mapper.select:
select task_department_checkpoint_id, company_id, task_id, department_id, status, require_evidence,
       evidence_note, evidence_ref, confirmed_by, confirmed_at, created_at, updated_at
from task_department_checkpoints
where company_id = #{companyId,jdbcType=VARCHAR}
  and task_id = #{taskId,jdbcType=VARCHAR}
order by created_at asc

select task_department_checkpoint_id, company_id, task_id, department_id, status, require_evidence,
       evidence_note, evidence_ref, confirmed_by, confirmed_at, created_at, updated_at
from task_department_checkpoints
where company_id = #{companyId,jdbcType=VARCHAR}
  and task_id = #{taskId,jdbcType=VARCHAR}
  and department_id = #{departmentId,jdbcType=VARCHAR}
limit 1

select count(1)
from task_department_checkpoints
where company_id = #{companyId,jdbcType=VARCHAR}
  and task_id = #{taskId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), 'PENDING')) != 'CONFIRMED'
